-- ----------------------------
-- Table structure for tb_document
-- ----------------------------
DROP TABLE IF EXISTS `tb_document`;
CREATE TABLE `tb_document`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '文档ID',
  `user_id` int NOT NULL COMMENT '用户ID',
  `filename` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '存储文件名（唯一标识）',
  `original_filename` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '原始文件名',
  `file_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '文件存储路径',
  `file_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '文件类型：txt, docx, pdf',
  `file_size` int NOT NULL COMMENT '文件大小（字节）',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'uploaded' COMMENT '状态：uploaded-已上传, parsed-已解析, processed-已处理, error-处理失败',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '解析后的文本内容',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '文档表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of tb_document
-- ----------------------------

-- ----------------------------
-- Table structure for tb_extraction_result
-- ----------------------------
DROP TABLE IF EXISTS `tb_extraction_result`;
CREATE TABLE `tb_extraction_result`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '抽取结果ID',
  `document_id` int NOT NULL COMMENT '文档ID',
  `task_id` int NOT NULL COMMENT '任务ID',
  `extraction_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '抽取类型：rule-规则抽取, algorithm-算法抽取',
  `field_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '字段名：date-日期, money-金额, person-人名, organization-机构, location-地点',
  `field_value` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '字段值',
  `confidence` float NULL DEFAULT NULL COMMENT '置信度（0-1）',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 89 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '信息抽取结果表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of tb_extraction_result
-- ----------------------------

-- ----------------------------
-- Table structure for tb_keyword_summary
-- ----------------------------
DROP TABLE IF EXISTS `tb_keyword_summary`;
CREATE TABLE `tb_keyword_summary`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '关键词摘要ID',
  `document_id` int NOT NULL COMMENT '文档ID',
  `task_id` int NOT NULL COMMENT '任务ID',
  `result_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '结果类型：keyword-关键词, summary-摘要',
  `algorithm` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '算法：TF-IDF, TextRank',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '关键词列表或摘要内容（JSON格式）',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 162 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '关键词和摘要结果表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of tb_keyword_summary
-- ----------------------------

-- ----------------------------
-- Table structure for tb_process_task
-- ----------------------------
DROP TABLE IF EXISTS `tb_process_task`;
CREATE TABLE `tb_process_task`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '任务ID',
  `document_id` int NOT NULL COMMENT '文档ID',
  `user_id` int NOT NULL COMMENT '用户ID',
  `task_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '任务类型：preprocess-预处理, extraction-信息抽取, keyword_summary-关键词摘要, annotation-数据标注, batch-批量处理',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending' COMMENT '状态：pending-待处理, processing-处理中, completed-已完成, failed-失败',
  `config` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '任务配置（JSON格式）',
  `result` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '处理结果（JSON格式）',
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '错误信息',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `completed_at` datetime NULL DEFAULT NULL COMMENT '完成时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 36 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '处理任务表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of tb_process_task
-- ----------------------------

-- ----------------------------
-- Table structure for tb_token
-- ----------------------------
DROP TABLE IF EXISTS `tb_token`;
CREATE TABLE `tb_token`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID，关联 tb_user.id',
  `token` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '登录令牌',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间(UTC)',
  `expires_at` datetime NOT NULL COMMENT '过期时间(UTC)',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_token`(`token` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  CONSTRAINT `tb_token_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `tb_user` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '登录Token表' ROW_FORMAT = DYNAMIC;

